13	export const quote = (items: Array<{ type: string }>, customer: unknown, contractNumber: number): number => {
14	  const totalPremium = items.reduce((sum, item) => {
15	    const basePremium = BASE_PREMIUMS[item.type] ?? 0;
16	    return sum + basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
17	  }, 0);
18	  return Math.ceil(totalPremium) + PROCESSING_FEE;
19	};
